import React from "react";
import { useNavigate } from "react-router-dom";

const Purpose = () => {
  const navigate = useNavigate();

  return (
    <div style={pageStyle}>
      <div style={cardStyle}>
        <h2>What brings you here?</h2>

        <button style={optionStyle}>Stress</button>
        <button style={optionStyle}>Depression</button>
        <button style={optionStyle}>Career</button>

        <button
          style={{ ...optionStyle, background: "#7b7cf6", color: "white" }}
          onClick={() => navigate("/dashboard")}
        >
          Continue
        </button>
      </div>
    </div>
  );
};

export default Purpose;

const pageStyle = {
  height: "100vh",
  display: "flex",
  justifyContent: "center",
  alignItems: "center",
  background: "#8f6cf5",
};

const cardStyle = {
  background: "white",
  padding: "40px",
  borderRadius: "12px",
  width: "400px",
  textAlign: "center",
};

const optionStyle = {
  width: "100%",
  padding: "12px",
  marginTop: "10px",
  border: "1px solid #ccc",
};
